from typing import Optional, Set

def find_roots(
    graph: "Graph", prop: "URIRef", roots: Optional[Set["Node"]] = None
) -> Set["Node"]:
    if roots is None:
        roots = set()

    all_nodes = {s for s, p, o in graph}
    child_nodes = {o for s, p, o in graph if p == prop}

    root_candidates = all_nodes - child_nodes
    roots.update(root_candidates)

    return roots

def _dump_string(obj, dumper=None):
    """
    Serializza in una stringa Unicode (Python 2) o in una stringa (Python 3).
    """
    if isinstance(obj, str):
        return obj
    elif isinstance(obj, bytes):
        return obj.decode('utf-8')
    elif isinstance(obj, unicode):  # For Python 2 compatibility
        return obj.encode('utf-8')
    else:
        raise TypeError("Object must be a string or bytes")

